esqlQuery.esql:
FROM metrics-traefik.otel-*
// Limit to process resident memory gauge (RSS)
| WHERE process_resident_memory_bytes IS NOT NULL
// Take max RSS in window
| STATS memory_bytes = MAX(process_resident_memory_bytes)
// Convert to GB; alert when > 2GB (tune based on expected workload)
| EVAL memory_gb = ROUND(memory_bytes / 1073741824.0, 2)
| WHERE memory_gb > 2.0
